window.__QUIZ_DATA__=[{"id":"theory>Geography>2022>1>a","subject":"Geography","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"List four modes of transportation","images":[],"marking_scheme":"-Land transportation  -Water transportation  -Air transportation  -Rail transportation","marks":"4","difficulty":"1"},{"id":"theory>Geography>2022>1>b","subject":"Geography","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Outline five reasons for the construction of railways in developing countries","images":[],"marking_scheme":"- To open up new areas for major crop production e.g Jos-Maiduguri  -To supply raw materials e.g East African railway  -To link important cities and facilitate movement of people e.g Abidjan-Ouagadougou  -To link different regions, thus promoting inter-regional trade e.g North and South of Nigeria  -To tap resources such as agricultural, mineral, forest etc. e.g Koura Namoda rail network","marks":"10","difficulty":"2"},{"id":"theory>Geography>2022>1>c","subject":"Geography","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Highlight three measures that can be taken to improve rail transportation in developing countries","images":[],"marking_scheme":"-Deliberate effort should be made towards the expansion of the rail network. This will generate growth in the economy    -Government should make capital available to railway authorities, this will enhance efficiency    -Training and retraining of personnel should be undertaken from time to time","marks":"6","difficulty":"2"},{"id":"theory>Geography>2022>2>a","subject":"Geography","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Distinguish between urbanization and population density","images":[],"marking_scheme":"Urbanization refers to the growth of towns, especially in terms of human population and physical size. In other words, urbanization means a change in the functions of a settlement from a rural character to an urban character while population density is defined as the number of persons per unit area of land or per square kilometre of land","marks":"4","difficulty":"3"},{"id":"theory>Geography>2022>2>b","subject":"Geography","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight four problems created by urbanization in Tropical Africa","images":[],"marking_scheme":"-Unemployment: Areas of high population usually do not have enough jobs for the ever increasing influx of people into such area. This is the cause of unemployment    -High cost of living: High population concentration of people leads to high cost of living as only few facilities and goods are available to the people and these tend to increase the cost of living.    -Environmental Pollution: More wastes are produced due to high concentration of people and these tends to cause pollution in the environment.    -Increased demand for social amenities: Social amenities like pipe-borne water, electricity, etc. will be in high demand when people migrate to urban area.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2022>2>c","subject":"Geography","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Highlight four problems created by urbanization in Tropical AfricaIn what four ways can the problems highlighted above be solved","images":[],"marking_scheme":"-To solve the problem of unemployment:  Creation of more jobs: Private investments should be encouraged so as to utilize natural resources and create more jobs opportunities. Tourism promotion and the sustainability exploitation of natural resources can create more jobs for urban populations.    -To solve the problem of high cost of living:  Provision of essential services: Urban stakeholders must ensure all populations within the urban areas have access to adequate essential social services namely education, health, sanitation, clean water, electricity and food. This is done so that people can earn a living to pay for the maintenance of the services. Subsidies can also be available by the government to lower the costs of basic healthcare, education, public transportation, communication systems and technology.    -To solve the problem of environmental pollution  Good Government Policies: Government should encourage sustainable use of urban resources and support an economy based on sustainable environment such as investment in green infrastructure, sustainable industries, recycling and environmental campaigns, pollution management, renewable energy, green public transportation and water recycling    -To solve the problem of increased demand for social amenities  Provision of Adequate Social Amenities: The government together with urban stakeholder should provide all populations within the urban areas with adequate social amenities such as good medical care, electricity etc.  Campaigns geared towards family planning should be provided to curb the problem of increased demand for social amenities.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2022>3>a","subject":"Geography","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"State four characteristics of local craft industries","images":[],"marking_scheme":"-Local craft industries make use of simple tools and their work is of high artistic quality  -They make use of a limited space as workshop  -They depend mainly on raw materials obtained from their immediate locality  -The prices of their works are negotiable","marks":"4","difficulty":"1"},{"id":"theory>Geography>2022>3>b","subject":"Geography","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Identify three limitations of local craft industries","images":[],"marking_scheme":"-Shortage of raw materials: Lack of sufficient raw materials available to local craft industries hinders production    -Competition from foreign goods: Due to the high quality of foreign goods, local goods produced by our local industries are usually not patronised    -Inadequate transport and communication facilities: Transportation network like road, rail etc. and communication facilities are grossly inadequate for local craft industries.    -Insufficient Capital: Access to finance or capital might be difficult for small time investors    -High degree of foreign dependence: Most locally made products are usually of low quality when compared to their counterparts in developed countries. Hence, people rely or depend on foreign goods","marks":"6","difficulty":"2"},{"id":"theory>Geography>2022>3>c","subject":"Geography","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Explain five factors that have contributed to the high volume of trade between the developed and Tropical African countries","images":[],"marking_scheme":"-Non-similarity of products: Both the developed and Tropical African countries produce goods that are not similar    -Colonial Ties: The inclination of some Tropical African countries to their colonial masters has helped to increase the volume of trade between the nations    -Preference for Imported Goods: Developing countries like Nigeria have preference for goods produced by developed countries, hence the high volume of trade    -Differences in Climate: There is difference in climate between some Tropical African Countries and some developed countries which results in the production of different agricultural products; hence an increase in the volume of trade between them    -Difference Import duties: There are higher differences in import duties of goods produced by both countries imposed on imported goods in both countries    -Absence of Trade Unions: There is absence of trade union between developing and advanced nations; hence the increase in the volume of trade","marks":"10","difficulty":"3"},{"id":"theory>Geography>2022>4>a","subject":"Geography","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria.  On the map, locate and name:  -Apapa seaport;  -Kainji dam;  -Abuja","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"3"},{"id":"theory>Geography>2022>4>b","subject":"Geography","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Highlight four benefits derived from the Hydro-Electric Power projects in Nigeria","images":[],"marking_scheme":"-It promotes irrigation agriculture through water trapped in the dams e.g Aswan Dam  -It helps to generate electricity(H.E.P) for domestic and industrial uses e.g Kainji Dam  -It also supplies water both for domestic and industrial use  -It provides employment to many people  -It proves food for man e.g prawns, crayfish etc. which grow in dams e.g Kainji Dam  -H.E.P projects or dams are centres of tourist; attraction and recreation","marks":"8","difficulty":"2"},{"id":"theory>Geography>2022>4>c","subject":"Geography","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Explain three advantages of seaports in Nigeria","images":[],"marking_scheme":"-Export of goods: Goods produced in Nigeria are exported to other countries through seaports    -Import of goods: Goods purchased from other countries are also brought into  the country through seaports, thereby promoting international trade    -Employment: Ports provide jobs for many people through various activities within the port e.g clearing agents exporters and importers    -Revenue to Government: Tariffs and demurrage from imported goods are sources of revenue to the government","marks":"6","difficulty":"2"},{"id":"theory>Geography>2022>5>a","subject":"Geography","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"List two crops that are cultivated under the bush fallowing system of farming in Nigeria","images":[],"marking_scheme":"-Root and Tuber Crops: Yam, cassava, cocoyam etc.  -Cereal(grain) crops: Rice, millet, maize, sorghum etc  -Berry: Tomato  -Cash crops: Cotton, Groundnut etc.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2022>5>b","subject":"Geography","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline five characteristics of bush fallowing system of farming in Nigeria","images":[],"marking_scheme":"-Farming is done on a subsistence level i.e farmers grow crops to feed themselves and their family  -It involves the use of crude implements like cutlass and hoe  -It uses slash or burn method for land preparations  -It uses family labour  -It is very common in rural areas with abundant farmlands  -Produce is usually very low and there is little or none for sale","marks":"10","difficulty":"2"},{"id":"theory>Geography>2022>5>c","subject":"Geography","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight four disadvantages of bush fallowing system of farming in Nigeria","images":[],"marking_scheme":"-It leads  to wastage of land which could have been used by allowing it to lie fallow  -It leads to land fragmentation due to increase in population  -It allows for cultivation of only one seasonal crops like maize, rice, millet etc  -It destroys valuable forest resources like timber  -It leads to soil erosion when the soil is exhausted","marks":"8","difficulty":"2"},{"id":"theory>Geography>2022>6>a","subject":"Geography","year":"2022","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria.  On the map, locate  and name  -Jos plateau;  -one river that flows into the Atlantic ocean;  -one natural lake;  -Port Harcourt","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"2"},{"id":"theory>Geography>2022>6>b","subject":"Geography","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Identify three problems of development in Lagos State","images":[],"marking_scheme":"-Water Pollution: This is a major problem of development in Lagos state. Uncontrolled disposal of raw sewage,sediments carrying runoff and effluents into the Lagoon system has created serious health concerns.    -Traffic Congestion: The rising car ownership and wealth have meant that more people own cars in lagos. These contribute to both noise and air pollution as well as lots of lost hours as people sit in traffic jams    -Electricity supply is limited: The sheer size of Lagos has overwhelmed the grid resulting in periods where the power cuts out","marks":"6","difficulty":"2"},{"id":"theory>Geography>2022>6>c","subject":"Geography","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Suggest three solutions to the problems of development in Lagos State","images":[],"marking_scheme":"-To solve the problem of water pollution:  Government should create policies for legislation against waste discharge into water and also enlighten citizens on the dangers of water pollution    -To solve the problem of traffic congestion:  Government should ensure construction of good and motorable roads with provision of traffic signs and traffic officials to ensure free flow of traffic.    -To solve the problem of limited electricity supply:  Upgrade of Power Distribution and Transmission Equipment: The lagos State government should embark on immediate upgrading of the power transmission and distribution of infrastructures.","marks":"6","difficulty":"2"}];